import React, { useState, useRef, useEffect } from 'react';
import { Send, User, Bot, Loader2, Trash2 } from 'lucide-react';
import { Message } from '../types';
import { getGeminiClient } from '../services/gemini';

const ChatInterface: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  const chatRef = useRef<any>(null);

  useEffect(() => {
    const ai = getGeminiClient();
    chatRef.current = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: "You are KRYVEX AI, a high-performance, futuristic synthetic intelligence. Your responses should be helpful, direct, and carry a sleek, high-tech persona. You use markdown for formatting.",
      }
    });
  }, []);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: input.trim(),
      timestamp: Date.now(),
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const response = await chatRef.current.sendMessage({ message: userMsg.content });
      const assistantMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: response.text || "I'm sorry, I couldn't process that.",
        timestamp: Date.now(),
      };
      setMessages(prev => [...prev, assistantMsg]);
    } catch (error) {
      console.error(error);
      const errorMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'system',
        content: "Error: Connection to KRYVEX nodes lost. Please try again.",
        timestamp: Date.now(),
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  const clearChat = () => {
    setMessages([]);
    const ai = getGeminiClient();
    chatRef.current = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: "You are KRYVEX AI, a high-performance, futuristic synthetic intelligence.",
      }
    });
  };

  return (
    <div className="flex-1 flex flex-col h-full max-w-5xl mx-auto w-full p-4 md:p-6">
      <div className="flex items-center justify-between mb-4 px-2">
        <h2 className="text-zinc-400 text-sm font-medium flex items-center gap-2">
          <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>
          GEMINI-3-FLASH NODE ACTIVE
        </h2>
        <button 
          onClick={clearChat}
          className="text-zinc-500 hover:text-white flex items-center gap-1 text-sm transition-colors"
        >
          <Trash2 size={14} /> Clear
        </button>
      </div>

      <div 
        ref={scrollRef}
        className="flex-1 overflow-y-auto space-y-6 mb-6 pr-2 scroll-smooth"
      >
        {messages.length === 0 ? (
          <div className="h-full flex flex-col items-center justify-center text-center space-y-4 opacity-40">
            <div className="w-16 h-16 rounded-3xl bg-white/5 flex items-center justify-center">
              <Bot size={32} />
            </div>
            <div>
              <p className="text-lg font-bold">KRYVEX Core Initialized</p>
              <p className="text-sm">Ready for high-fidelity text processing.</p>
            </div>
          </div>
        ) : (
          messages.map((m) => (
            <div key={m.id} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[85%] rounded-2xl p-4 flex gap-4 ${
                m.role === 'user' 
                  ? 'bg-pink-600/10 border border-pink-500/20 text-pink-50' 
                  : m.role === 'system'
                  ? 'bg-red-500/10 border border-red-500/30 text-red-400 text-sm'
                  : 'bg-white/5 border border-white/10 text-zinc-300'
              }`}>
                <div className={`w-8 h-8 rounded-lg flex-shrink-0 flex items-center justify-center ${
                  m.role === 'user' ? 'bg-pink-500' : 'bg-zinc-800'
                }`}>
                  {m.role === 'user' ? <User size={16} /> : <Bot size={16} />}
                </div>
                <div className="flex-1 overflow-x-auto">
                  <p className="whitespace-pre-wrap leading-relaxed">{m.content}</p>
                </div>
              </div>
            </div>
          ))
        )}
        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-white/5 border border-white/10 rounded-2xl p-4 flex items-center gap-3">
              <Loader2 size={18} className="animate-spin text-pink-500" />
              <span className="text-sm text-zinc-400">Processing input...</span>
            </div>
          </div>
        )}
      </div>

      <div className="relative group">
        <input 
          type="text" 
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && handleSend()}
          placeholder="Command KRYVEX AI..." 
          className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-5 pr-16 focus:border-pink-500/50 focus:ring-1 focus:ring-pink-500/20 outline-none transition-all placeholder:text-zinc-600"
        />
        <button 
          onClick={handleSend}
          disabled={!input.trim() || isLoading}
          className={`absolute right-3 top-1/2 -translate-y-1/2 p-3 rounded-xl transition-all ${
            input.trim() && !isLoading ? 'bg-pink-500 text-white shadow-lg shadow-pink-500/20' : 'bg-white/5 text-zinc-600'
          }`}
        >
          <Send size={20} />
        </button>
      </div>
      <p className="text-[10px] text-zinc-600 text-center mt-3 uppercase tracking-widest">
        KRYVEX Synthetic Reasoning Model 3.0-Flash-Preview
      </p>
    </div>
  );
};

export default ChatInterface;

import React, { useState } from 'react';
import { ImageIcon, Sparkles, Download, Loader2, RefreshCw } from 'lucide-react';
import { generateImage } from '../services/gemini';
import { GeneratedImage } from '../types';

const ImageGenerator: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [images, setImages] = useState<GeneratedImage[]>([]);

  const handleGenerate = async () => {
    if (!prompt.trim() || isGenerating) return;

    setIsGenerating(true);
    try {
      const url = await generateImage(prompt);
      const newImg: GeneratedImage = {
        id: Date.now().toString(),
        url,
        prompt,
        timestamp: Date.now(),
      };
      setImages(prev => [newImg, ...prev]);
      setPrompt('');
    } catch (error) {
      console.error(error);
      alert("System overload: Image synthesis failed.");
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="flex-1 flex flex-col md:flex-row h-full overflow-hidden">
      {/* Sidebar Controls */}
      <div className="w-full md:w-80 border-r border-white/10 p-6 flex flex-col gap-6 bg-white/[0.01]">
        <div>
          <h3 className="text-lg font-bold flex items-center gap-2 mb-2">
            <Sparkles size={18} className="text-pink-500" />
            Image Synthesis
          </h3>
          <p className="text-xs text-zinc-500 uppercase tracking-widest">Model: Gemini 2.5 Flash Image</p>
        </div>

        <div className="space-y-4">
          <label className="text-xs font-bold text-zinc-400 uppercase tracking-wider">Prompt Interface</label>
          <textarea 
            value={prompt}
            onChange={(e) => setPrompt(e.target.value)}
            placeholder="A cinematic neon landscape of Tokyo in 2099, highly detailed, photorealistic 8k..."
            className="w-full bg-white/5 border border-white/10 rounded-xl p-4 h-32 focus:border-pink-500/50 outline-none transition-all text-sm resize-none"
          />
          <button 
            onClick={handleGenerate}
            disabled={!prompt.trim() || isGenerating}
            className={`w-full py-4 rounded-xl font-bold flex items-center justify-center gap-2 transition-all ${
              prompt.trim() && !isGenerating 
                ? 'bg-pink-500 hover:bg-pink-600 shadow-lg shadow-pink-500/20' 
                : 'bg-white/10 text-zinc-500 cursor-not-allowed'
            }`}
          >
            {isGenerating ? <Loader2 className="animate-spin" size={20} /> : <Sparkles size={20} />}
            {isGenerating ? 'Generating...' : 'Synthesize Image'}
          </button>
        </div>

        <div className="mt-auto pt-6 border-t border-white/10 text-[10px] text-zinc-600 leading-relaxed uppercase tracking-tighter">
          Resolution: 1024x1024<br/>
          Format: PNG lossless<br/>
          API Latency: Optimized
        </div>
      </div>

      {/* Main Grid View */}
      <div className="flex-1 overflow-y-auto p-6 md:p-10 bg-[#0c0c0c]">
        {images.length === 0 ? (
          <div className="h-full flex flex-col items-center justify-center text-center space-y-6">
            <div className="w-24 h-24 rounded-[2rem] bg-white/[0.03] flex items-center justify-center border border-white/[0.05]">
              <ImageIcon size={48} className="text-zinc-700" />
            </div>
            <div className="max-w-md">
              <h4 className="text-2xl font-bold text-zinc-400 mb-2">No Visuals Generated</h4>
              <p className="text-zinc-600">Enter a descriptive prompt on the left to begin synthetic image generation.</p>
            </div>
          </div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-3 gap-6">
            {images.map((img) => (
              <div key={img.id} className="group relative aspect-square rounded-2xl overflow-hidden bg-zinc-900 border border-white/10">
                <img src={img.url} alt={img.prompt} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110" />
                <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/20 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300 p-4 flex flex-col justify-end">
                  <p className="text-xs text-white line-clamp-2 mb-3">{img.prompt}</p>
                  <div className="flex items-center gap-2">
                    <button 
                      onClick={() => {
                        const link = document.createElement('a');
                        link.href = img.url;
                        link.download = `kryvex-ai-${img.id}.png`;
                        link.click();
                      }}
                      className="p-2 bg-white/10 hover:bg-white/20 rounded-lg text-white transition-colors"
                    >
                      <Download size={16} />
                    </button>
                    <button className="p-2 bg-white/10 hover:bg-white/20 rounded-lg text-white transition-colors">
                      <RefreshCw size={16} />
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default ImageGenerator;

import React, { useState, useEffect } from 'react';
import { Video, Film, Download, Loader2, AlertCircle, Info, Key } from 'lucide-react';
import { startVideoGeneration, pollVideoOperation, downloadVideo } from '../services/gemini';
import { GeneratedVideo } from '../types';

declare global {
  interface Window {
    aistudio: {
      hasSelectedApiKey: () => Promise<boolean>;
      openSelectKey: () => Promise<void>;
    };
  }
}

const VideoGenerator: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [hasKey, setHasKey] = useState(false);
  const [status, setStatus] = useState<string>('');
  const [videos, setVideos] = useState<GeneratedVideo[]>([]);

  useEffect(() => {
    const checkKey = async () => {
      const selected = await window.aistudio.hasSelectedApiKey();
      setHasKey(selected);
    };
    checkKey();
  }, []);

  const handleKeySelect = async () => {
    await window.aistudio.openSelectKey();
    setHasKey(true);
  };

  const handleGenerate = async () => {
    if (!prompt.trim() || isGenerating || !hasKey) return;

    setIsGenerating(true);
    setStatus('Initializing Veo clusters...');

    try {
      let operation = await startVideoGeneration(prompt);

      const poll = async () => {
        while (!operation.done) {
          setStatus('Synthesizing frames (this may take a few minutes)...');
          await new Promise(resolve => setTimeout(resolve, 8000));
          operation = await pollVideoOperation(operation);
        }

        const uri = operation.response?.generatedVideos?.[0]?.video?.uri;
        if (uri) {
          setStatus('Downloading final render...');
          const localUrl = await downloadVideo(uri);
          const newVid: GeneratedVideo = {
            id: Date.now().toString(),
            url: localUrl,
            prompt,
            timestamp: Date.now(),
          };
          setVideos(prev => [newVid, ...prev]);
        }
      };

      await poll();
      setPrompt('');
    } catch (error: any) {
      console.error(error);
      if (error?.message?.includes('Requested entity was not found')) {
        setHasKey(false);
        alert("Session expired. Please re-authenticate your API key.");
      } else {
        alert("Generative error: Video pipeline failed.");
      }
    } finally {
      setIsGenerating(false);
      setStatus('');
    }
  };

  if (!hasKey) {
    return (
      <div className="flex-1 flex items-center justify-center p-6 text-center">
        <div className="max-w-md p-8 rounded-[2.5rem] bg-white/[0.02] border border-white/10 space-y-6">
          <div className="w-20 h-20 rounded-3xl kryvex-gradient flex items-center justify-center mx-auto mb-4">
            <Key size={40} className="text-white" />
          </div>
          <h2 className="text-3xl font-black">Authentication Required</h2>
          <p className="text-zinc-500 text-sm">
            High-fidelity video synthesis requires a verified Billing API Key from Google AI Studio.
          </p>
          <div className="p-4 rounded-xl bg-blue-500/10 border border-blue-500/20 text-blue-400 text-xs text-left flex gap-3">
            <Info size={24} className="flex-shrink-0" />
            <p>Ensure you have a paid project enabled. <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" className="underline font-bold">Billing Docs</a></p>
          </div>
          <button 
            onClick={handleKeySelect}
            className="w-full py-4 bg-white text-black font-bold rounded-xl hover:bg-zinc-200 transition-colors"
          >
            Select API Key
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="flex-1 flex flex-col md:flex-row h-full overflow-hidden">
      <div className="w-full md:w-80 border-r border-white/10 p-6 flex flex-col gap-6 bg-white/[0.01]">
        <div>
          <h3 className="text-lg font-bold flex items-center gap-2 mb-2">
            <Film size={18} className="text-pink-500" />
            Video Synthesis
          </h3>
          <p className="text-xs text-zinc-500 uppercase tracking-widest">Model: Veo 3.1 Fast Preview</p>
        </div>

        <div className="space-y-4">
          <label className="text-xs font-bold text-zinc-400 uppercase tracking-wider">Cinematic Prompt</label>
          <textarea 
            value={prompt}
            onChange={(e) => setPrompt(e.target.value)}
            placeholder="A drone shot flying through a neon-lit cyber-city, rain splashing on glass, cinematic lighting..."
            className="w-full bg-white/5 border border-white/10 rounded-xl p-4 h-32 focus:border-pink-500/50 outline-none transition-all text-sm resize-none"
          />
          <button 
